class Solution {
public:
    int maxScore(vector<int>& nums) {
        int n = nums.size() / 2;
        sort(nums.rbegin(), nums.rend());
        int res = 0;
        for (int i = 0; i < n; i++) {
            res += (i + 1) * gcd(nums[2 * i], nums[2 * i + 1]);
        }
        return res;
    }
};
```
